      const _avgFeedCount = _heroGsRecent.length > 0 ? Math.round(_heroGsRecent.reduce((s,rd) => s + rd.entries.filter(e=>e.type==="feed"&&!e.night).length, 0) / _heroGsRecent.length) : 0;
