    const _nightSleeps = _recent7.map(d => {
      const nw = getNightWindows(days[d] || [], days[_dk[_dk.indexOf(d) + 1]] || []);
      return nw.reduce((s, w) => s + w.mins, 0);
    }).filter(v => v > 120);
